73	static void synthesizeScopeForFunction(FunctionOpInterface funcOp,
74	                                       DICompileUnitAttr compileUnitAttr) {
75	  MLIRContext *context = funcOp.getContext();
76	  Location loc = funcOp.getLoc();
77	
78	  // Skip functions that already have a scope.
79	  if (loc->findInstanceOf<DILocAttr>())
80	    return;
